package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintReturnsCSVPrinter() throws IOException {
        Appendable appendable = new StringBuilder();
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);
        assertSame(appendable, getField(printer, "out"));
        assertSame(csvFormat, getField(printer, "format"));
    }

    // Reflection helper to get private field value, including from superclass if needed
    private Object getField(Object object, String fieldName) {
        Class<?> clazz = object.getClass();
        while (clazz != null) {
            try {
                java.lang.reflect.Field field = clazz.getDeclaredField(fieldName);
                field.setAccessible(true);
                return field.get(object);
            } catch (NoSuchFieldException e) {
                clazz = clazz.getSuperclass();
            } catch (Exception e) {
                fail("Failed to get field '" + fieldName + "' via reflection: " + e.getMessage());
                return null;
            }
        }
        fail("Field '" + fieldName + "' not found in class hierarchy");
        return null;
    }
}
